import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import java.util.HashMap;
import java.util.Map;
import org.xml.sax.SAXException;

public class XMLParser {

 private static final Map<String, String> parseXml(Document doc) throws IllegalArgumentException {
 Map<String, String> config = new HashMap<>();
 NodeList nodeList = doc.getElementsByTagName("setting");

 for (int i = 0; i < nodeList.getLength(); i++) {
 Node currentNode = nodeList.item(i);
 if (currentNode.getNodeType() == Node.ELEMENT_NODE) {
 Element element = (Element) currentNode;
 config.put(element.getAttribute("name"), element.getTextContent());
 }
 }
 return config;
 }

 public static Map<String, String> parseConfig(InputStream inputStream) throws SAXException, IOException {
 DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
 DocumentBuilder builder = factory.newDocumentBuilder();
 Document document = builder.parse(inputStream);
 return parseXml(document);
 }
}